INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('mcp-github-com-bullobi-amap-full-nav-weather-traffic', 'mcp', 'amapfullnavweathertraffic', '基于高德地图开放平台MCP Server 2.', '基于高德地图开放平台MCP Server 2.0，集成实时天气查询、多模式路线规划（驾车/步行/骑行/公交）、红绿灯实时状态、一键导航跳转、POI搜索、逆地理编码、IP定位、距离测算等全栈出行能力，支持红绿灯倒计时、路线避堵、多终点规划、天气预警联动，为AI提供完整的出行与地理服务能力。', 'gh_-96310343711987', 'gh_255633715', 'search_research', 'changes_requested', '2026-03-16T09:42:36Z', '2026-05-02T08:26:37Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('mcp-github-com-bullobi-amap-nav-weather', 'mcp', 'amapnavweather', '基于高德地图，提供天气查询、路线规划、红绿灯提示、一键导航等实用出行服务，支持驾车、步行、公交等多种出行方式。', '基于高德地图，提供天气查询、路线规划、红绿灯提示、一键导航等实用出行服务，支持驾车、步行、公交等多种出行方式。', 'gh_-96310343711987', 'gh_255633715', 'search_research', 'changes_requested', '2026-03-16T09:38:08Z', '2026-03-23T03:20:18Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('mcp-github-com-cantian-ai-bazi-mcp', 'mcp', 'bazi', 'bazi', 'bazi工具包提供专业的八字命理查询功能，支持通过公历或农历时间获取详细八字信息，并能根据八字反推可能的公历时间。同时可查询指定日期的黄历宜忌，帮助用户进行传统命理分析和择日参考。', 'gh_-207714417220318', 'gh_66207760', 'dev_code', 'changes_requested', '2025-09-25T16:36:47Z', '2025-09-25T16:36:47Z', NULL);
