INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('mcp-github-com-dandanllab-legadoskill', 'mcp', 'legado书源驯兽师', 'Legado书源驯兽师是一个基于大语言模型的智能书源开发辅助工具，专门用于辅助Legado（阅读）Android应用的书源开发。', 'Legado书源驯兽师是一个基于大语言模型的智能书源开发辅助工具，专门用于辅助Legado（阅读）Android应用的书源开发。通过AI技术自动分析网站结构，生成符合Legado规范的书源JSON，让书源开发变得简单高效。', 'gh_-123221059105767', 'gh_104361379', 'dev_code', 'changes_requested', '2026-05-31T22:19:49Z', '2026-06-04T10:28:07Z', NULL);
