INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('mcp-issue-61', 'mcp', '抓取网页', '一个提供网页内容抓取功能的模型上下文协议服务器。此服务器使大型语言模型能够从网页中检索和处理内容，并将 HTML 转换为 markdown 以便更容易地使用。', '一个提供网页内容抓取功能的模型上下文协议服务器。此服务器使大型语言模型能够从网页中检索和处理内容，并将 HTML 转换为 markdown 以便更容易地使用。

获取工具会截断响应，但通过使用 start_index 参数，您可以指定从何处开始提取内容。这让模型可以分块读取网页，直到找到所需的信息。

可用工具
fetch - 从互联网上抓取一个 URL 并将其内容作为 markdown 提取。
url (字符串, 必需): 要抓取的 URL
max_length (整数, 可选): 返回的最大字符数 (默认: 5000)
start_index (整数, 可选): 从此字符索引开始提取内容 (默认: 0)
raw (布尔值, 可选): 获取未经 markdown 转换的原始内容 (默认: false)
提示
fetch
抓取一个 URL 并将其内容作为 markdown 提取
参数:
url (字符串, 必需): 要抓取的 URL', 'gh_127482729', 'gh_127482729', 'search_research', 'withdrawn', '2026-04-17T00:28:44Z', '2026-04-17T16:01:48Z', NULL);
