INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-loki-sticker-renderer', 'package', '表情包渲染器 v0.7.2', '让AI可以在正常对话模式下发送本地或外链表情包，且无需输出md代码。插件会自动匹配并渲染出相应的表情包图片。 插件开启即可使用，无需调用工具。仅在前端渲染，不改变后端内容。', '将聊天消息中的 <meme>表情名</meme> 或 <sticker>表情名</sticker> XML 标签渲染为本地或外链表情包图片，支持自定义目录、外链列表、自动扫描、后缀补全和角色分配置。本地目录自动扫描需要 Shizuku 权限；未开启 Shizuku 时可使用外链列表。', 'gh_242139992', 'gh_242139992', 'media_content', 'approved', '2026-05-16T06:52:55Z', '2026-05-18T13:00:05Z', '2026-05-16T06:52:55Z');
