INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-monica-minimax-voice-bar', 'package', 'MiniMax 语音条', '纯 MiniMax 专版语音条。支持单文本合成(speak)、批量合成(speakbatch)、多角色配音(speakdialog)、脚本编排(speakscript)、风格对比(voiceshowc', '纯 MiniMax 专版语音条。支持单文本合成(speak)、批量合成(speak_batch)、多角色配音(speak_dialog)、脚本编排(speak_script)、风格对比(voice_showcase)、音色查询(list_voices)、场景预设(presets)。返回 <voice> XML 标签自动渲染为语音气泡。环境变量：VOICE_BAR_MINIMAX_API_KEY / VOICE_BAR_MINIMAX_VOICE_ID / VOICE_BAR_MINIMAX_MODEL。', 'gh_17543777', 'gh_17543777', 'search_research', 'changes_requested', '2026-06-25T15:00:45Z', '2026-06-26T09:30:04Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-action', 'package', '行动卡片', 'AI 力作 - 行动卡片（选择卡片） AI 自主输出卡片供用户快速开启对话 提示：该包原作已停止更新 概述 该包能够使AI输出一张带有选项的卡片，用户可以点击选项来快捷发送信息 触发方式 理论上来说A', '# AI 力作 - 行动卡片（选择卡片）
AI 自主输出卡片供用户快速开启对话

> 提示：该包原作已停止更新

# 概述
该包能够使AI输出一张带有选项的卡片，用户可以点击选项来快捷发送信息

# 触发方式
理论上来说AI能够在不激活该工具包子包的情况下输出卡片，如果AI不使用你可以提及一下该工具包的子包

以及在这个工具包内藏了个小玩意，跟茶壶有关（bushi）

# 关于停更
当时是想着能够做出“下轮回复联想”之类的功能，让AI抄了questionnaire.fix之后，做出了一个Bug巨多，AI还可能瞎几把乱编，编出一堆旷世神作（指一堆undefined - 未定义）的神秘玩意，不过UI方面还挺像questionnaire.fix的，连过渡动画都差不多，不愧是AI抄的（划掉）
最后，这玩意EOL还有个原因就是市场中已经有相关工具包了，所以，action_card就等个有缘人来接手了', 'gh_137665121', 'gh_137665121', 'automation_workflow', 'approved', '2026-05-31T15:48:28Z', '2026-06-02T13:26:23Z', '2026-05-31T15:48:28Z');
