INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-context-limiter-pro', 'package', '楼层限制器Pro', '双模式楼层限制器。保留最近N条消息 / 从第N条消息开始保留。按对话窗口独立设置。UI页面可手动输入，输入框旁toggle可开关。', '双模式楼层限制器。保留最近N条消息 / 从第N条消息开始保留。按对话窗口独立设置。UI页面可手动输入，输入框旁toggle可开关。
——
在万古（阿平）的楼层限制器基础上做了改动，让其可以在特定楼层开始发送上下文，前文截取后不发送
——
使用方式（两种入口）

① UI页面（推荐，不花工具调用）
- 打开工具箱/侧边栏 → 「楼层限制器」
- 自动检测或手动输入对话 ID
- 开关、切模式、输入数字、保存，全在 UI 里完成
- 可滚动页面

② 输入框菜单 Toggle（快速开关）
- 聊天输入框旁的菜单里有「楼层限制器」开关
- 点击即可开关当前对话的限制器

③ 子包工具（AI 可调）
- `set_mode` — 设置模式
- `set_floor_limit` — 设置保留条数
- `set_start_floor` — 设置起始楼层
- `toggle` — 开关
- `get_config` — 查看当前配置
——
使用总结的话，请勿使用此插件
API支持缓存请用特定楼层限制
API不支持缓存请用轮次限制
——
插件本身有很多的问题
除了上面的使用教程
1.在装插件之前没有数据的对话，只能够简单的除以二获取大概的用户发送消息楼层数
2.没办法在前端显示用户发送消息楼层数，每一次用户输入的数字都只能是预估楼层位置。推荐搭配【消息调试转储】使用
3.每次都要进入UI才能够修改数字，或者是让机调用工具改。没办法在菜单改了，因为数字不是轮回滚动而是越来越大……
4.没有进行很多的测试……我不知道有没有BUG
——
