INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-questionnaire', 'package', '问卷提问', '一个让 AI 能够按需向用户发送结构化问卷的工具包。当 AI 需要同时获取多条信息时，可以通过 questionnaire:ask 工具发出一份包含单选、多选、文本输入的表单，用户逐题作答后统一提交。', '一个让 AI 能够按需向用户发送结构化问卷的工具包。当 AI 需要同时获取多条信息时，可以通过 questionnaire:ask 工具发出一份包含单选、多选、文本输入的表单，用户逐题作答后统一提交。

不同于逐条提问的零碎对话，问卷表单将多个问题组织在一张卡片中，用户可以一次性浏览所有问题、自由切换选项、随时折叠/展开，填写体验更连贯。

▸ 三种题型
  • single — 单选 (RadioButton → OutlinedButton 紧凑布局)
  • multiple — 多选 (Checkbox → OutlinedButton 紧凑布局)
  • text — 自由文本输入

▸ 交互方式
  • 点击标题栏的箭头图标可折叠/展开表单
  • 填完点右下角 ✓ 提交按钮，答案以 标题: 答案 格式发回聊天
  • 未填的题目自动忽略，不强制填写
  • 提交后表单自动折叠为 Q&A 视图（问题+主题色答案）

▸ 视觉特性
  • Material3 主题色适配
  • Material Icons 箭头 (keyboard_arrow_right / keyboard_arrow_down)
  • OutlinedButton 选项按钮，选中态主题色填充
  • 提交按钮下方有分割线区分内容区与操作区
  • 整行标题可点击

▸ 典型使用场景
  • 收集项目需求（平台、功能、技术栈等多维度）
  • 故障排查信息采集（系统版本、错误日志、复现步骤）
  • 配置信息录入（包名、权限、端点等多项参数）
  • 任何需要用户同时提供多个信息的场景

▸ 使用方式
  AI 调用 questionnaire:ask 工具，传入问卷标题和问题列表（JSON），
  工具返回 XML 标签，AI 在回复中输出该标签后自动渲染为表单。

▸ 版本: 0.1.0', 'gh_103719318', 'gh_103719318', 'chat_communication', 'approved', '2026-05-24T06:49:31Z', '2026-05-30T08:51:17Z', '2026-05-24T06:49:31Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-questionnaire-fix', 'package', '问卷提问（第三方修复版）', '问卷提问 Questionnaire 更新内容（v1.5.', '问卷提问 | Questionnaire
更新内容（v1.5.2）
这次主要改动了问卷脚本式（还是保留旧版的渲染）
这一次性一口气添加了一大堆奇奇怪怪的功能：
现在推出：QLang V2 - 基于C++仿写的问卷脚本语言
1.大改脚本式逻辑，反正更稳定了就对了
2.添加了许多新的功能，从脚本的定义到运行到输出都有很大改动和升级，此外运行持续时长从5s调整到了10s（用于跑算法才搞这么久的运行时限）
3.运行时稍稍加强了一下
4.此外，该项目的完整源码在 Github 上开源了：github.com/yyswys-yjyj/questionnaire，如果你发现了 bug，欢迎在该项目上提个 issue

然后是画饼环节：
未来打算整一个引入外部问卷脚本（qlg）文件功能，这样问卷脚本就不用每次写一遍了（也可以当头文件使）', 'gh_137665121', 'gh_137665121', 'dev_code', 'approved', '2026-05-27T10:08:27Z', '2026-06-18T17:35:52Z', '2026-05-27T10:08:27Z');
