INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-quiz-card', 'package', '答题卡片', '特点在于答题卡片在对话框，是从文本里直接获取的，不占输出token 我的题库都是pdf的，所以需要ocr，百度这个有免费额度，教程尽量清晰了，不懂还是问ai吧 下面是ai写的介绍 📚 【答题卡片】让', '特点在于答题卡片在对话框，是从文本里直接获取的，不占输出token
我的题库都是pdf的，所以需要ocr，百度这个有免费额度，教程尽量清晰了，不懂还是问ai吧

下面是ai写的介绍
📚 【答题卡片】让 AI 陪你做练习题！
⭐ 核心功能
• 对话式答题卡片，支持单选/多选，自动判分
• 逐题显示解析，答完生成成绩报告
• 题库架管理已导入题库
• 拍照发图自动识别导入题库（需配百度 OCR）

📖 快速上手
1️⃣ 安装本包后，打开侧边栏「题库架」
2️⃣ 点击右上角「导入」→ 选择 JSON 题库文件
3️⃣ 对 AI 说「开始答题」即可

📷 OCR 导入（可选）
首次使用需要配置百度 OCR API Key（免费）：
