INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-worldbook-fixed', 'package', '世界书修复版', '世界书/知识库插件，支持创建、编辑、启用/禁用世界书条目，并通过关键词或常驻激活自动注入到系统提示词或用户消息中。', '世界书/知识库插件，支持创建、编辑、启用/禁用世界书条目，并通过关键词或常驻激活自动注入到系统提示词或用户消息中。', 'gh_251724981', 'gh_251724981', 'docs_knowledge', 'approved', '2026-05-13T06:09:17Z', '2026-05-14T15:01:01Z', '2026-05-13T06:09:17Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-operit-worldbook-plus', 'package', '世界书plus', 'v1.1.1 更新日志 修复 Bug：分组角色卡绑定失效 当世界书条目放在某个分组下（分组已绑定特定角色卡），但条目自身未绑定角色卡时，该条目会泄漏到所有角色卡的对话中被错误注入。', '**v1.1.1 更新日志**

**修复 Bug：分组角色卡绑定失效**

当世界书条目放在某个分组下（分组已绑定特定角色卡），但条目自身未绑定角色卡时，该条目会泄漏到**所有角色卡**的对话中被错误注入。

**根因**：角色卡匹配逻辑只检查条目自身的 `character_card_id`，完全忽略了所在分组的 `character_card_ids` 绑定关系。

**修复**：匹配逻辑改为三级优先级判断：
1. 条目自身绑定了角色卡 → 仅对该角色卡生效
2. 条目未绑定，但所在分组绑定了角色卡 → 仅对分组绑定的角色卡生效
3. 条目未绑定、所在分组也未绑定 → 才作为全局条目生效

**影响范围**：`systemPromptHook`、`finalizeHook`、`syncWorldBookVariableContext` 三处注入链路均已同步修复。
