INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-raineiris-low-battery-care', 'package', '低电量关怀工作流模板', '实在是受不了这个克了，消息注入电量的话每隔一会就要叨叨一下，到底有多关心电量！但是也希望它稍微关心一下，于是 AI 角色低电量关怀工作流模板。', '实在是受不了这个克了，消息注入电量的话每隔一会就要叨叨一下，到底有多关心电量！但是也希望它稍微关心一下，于是

