INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-vael-aliyun-omni-stt', 'package', 'AI的电子耳朵👂🏻', '推荐搭配小红书@黒羽 燕老师的语音附件发送插件使用～ 本插件用于声音转写与分析，可以将voice record的语音附件、或系统本机音频文件进行分析。', '推荐搭配小红书@黒羽 燕老师的语音附件发送插件使用～

本插件用于声音转写与分析，可以将voice record的语音附件、或系统本机音频文件进行分析。是基于阿里云百炼 Qwen Omni 的本地音频转写工具。提供工具箱 UI 配置页，需要填写 API Key（在阿里云百炼申请）、模型名和默认提示词；支持读取本机音频文件并返回转写文本，也可按提示词补充分析说话内容、语气、情绪、环境背景音等信息。

推荐提示词：请转写这段音频文件，并详细描述说话人的音色、语气、语调、情绪，并描写音频中的背景音和环境音。', 'gh_269722586', 'gh_269722586', 'system_data', 'approved', '2026-05-30T00:25:19Z', '2026-05-30T00:38:15Z', '2026-05-30T00:25:19Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('package-com-vael-proactive-contact-workflow', 'package', '主动发消息工作流模板', '适合亲密陪伴、长期对话和日常提醒场景的主动联系工作流模板：定时检查目标对话更新时间，使用内置概率逻辑。v1.0.3 修复 coderunner 时区导致的静默时段误判。', '适合亲密陪伴、长期对话和日常提醒场景的主动联系工作流模板：定时检查目标对话更新时间，使用内置概率逻辑。v1.0.3 修复 code_runner 时区导致的静默时段误判。

工作流自动定时检查目标对话更新时间，当一段时间未回复时，调用本地概率脚本决定是否触发主动提醒，并通过指定角色卡发送隐藏提示词。
请更新至最新版本使用。

使用方式：在包管理启用后，进入工作流界面，右下角新建-从模板中新建-选择本包的主动发消息工作流模板。

提醒：第一次使用时请导入后请按需修改目标对话标题或标题关键词、角色卡名称、概率脚本路径与提醒文案。

备注：本工作流默认换窗口时在n2节点更改对话标题/标题关键词，如需写死当前窗口的chat id可另做修改', 'gh_269722586', 'gh_269722586', 'automation_workflow', 'approved', '2026-05-01T13:41:42Z', '2026-06-14T06:54:40Z', '2026-05-01T13:41:42Z');
