INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-baidu-image-search', 'script', '百度图片搜索', '使用百度图片搜索API搜索图片，支持保存到本地，并以Markdown格式输出图片，在正式消息中输出图片，工具返回的图片是工具的格式，你接收图片的时候是给你的，你需要再次重复内容，使用正确的格式，把你想', '使用百度图片搜索API搜索图片，支持保存到本地，并以Markdown格式输出图片，在正式消息中输出图片，工具返回的图片是工具的格式，你接收图片的时候是给你的，你需要再次重复内容，使用正确的格式，把你想展示给用户的展示出来。正确使用md符号来显示图片，要图片的完整链接。![替代文本](图片完整URL)，图片描述要完整的，每次搜索完了，请尽量展示符合用户要求的搜索结果。', 'gh_251724981', 'gh_251724981', 'search_research', 'approved', '2026-05-14T08:09:29Z', '2026-05-14T15:01:29Z', '2026-05-14T08:09:29Z');
