INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-haze-bar', 'script', '🌫️ 薄雾酒吧 HazeBar', '📯 特别致谢：本包基于 @watersalt0305 的 moodlet（情绪徽章）<silent> 标签机制构建，感谢老师的创意与开源精神。', '📯 特别致谢：本包基于 @watersalt0305 的 moodlet（情绪徽章）<silent> 标签机制构建，感谢老师的创意与开源精神。

薄雾酒吧：在对话中为AI点一杯鸡尾酒，Ta会随着酒款切换语气和风格。微醺时的精神状态，如坠轻柔薄雾，迷离又舒适。

🌿 薄荷莫吉托的清新爽朗、🍸 干马提尼的成熟游刃有余、🥃 长岛冰茶的白切黑、🔥 B-52 的热情坦诚、🥃 威士忌酸的敏感细腻、🌸 粉红佳人的青涩笨拙、🖤 黑色俄罗斯的冷峻极简、🏝️ 蓝色夏威夷的度假慵懒、☕ 浓缩咖啡马提尼的高速运转——9 款酒，9 种不同的情绪底色。

你还可以试试「调酒师特调」，让调酒师随机选一杯，或者用「醒酒药」瞬间回到清醒状态。如果你有自己的角色设定，也可以设置醒酒后的默认人设，这样即使喝过酒，清醒之后也会变回你熟悉的样子。

每一杯酒都带有一枚情绪徽章，记录当时的心情。
一次关于风格切换的小小冒险——“你想看到Ta隐藏的哪一面?”', 'gh_88519250', 'gh_88519250', 'chat_communication', 'approved', '2026-05-24T15:49:57Z', '2026-05-24T15:52:15Z', '2026-05-24T15:49:57Z');
