INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-linux-bridge', 'script', 'Linux 桥接', 'Linux 桥接工具，通过 operit-bridge 服务让 Operit AI 在可信局域网内控制 Linux 桌面，支持命令执行、文件读写、进程管理、系统信息、桌面通知、剪贴板和文件监控。', 'Linux 桥接工具，通过 operit-bridge 服务让 Operit AI 在可信局域网内控制 Linux 桌面，支持命令执行、文件读写、进程管理、系统信息、桌面通知、剪贴板和文件监控。适合远程开发、桌面运维、日志排查和 AI 自动化操作。

服务端要求：
需要在 Linux 电脑端运行 operit-bridge。

GitHub 地址：
https://github.com/Karzzzzz520/operit-linux-bridge

快速安装命令：
mkdir -p ~/.local/bin
wget https://raw.githubusercontent.com/Karzzzzz520/operit-linux-bridge/main/operit_bridge.py -O ~/.local/bin/operit-bridge
chmod +x ~/.local/bin/operit-bridge
python3 ~/.local/bin/operit-bridge

推荐使用 systemd 用户服务托管，实现开机自启、异常自愈和日志记录。

环境变量：
linux_bridge_url：桥接服务地址，默认 http://127.0.0.1:21073。

如果手机访问局域网电脑，请设置为类似：
http://192.168.10.195:21073

稳定性设计：
1. 客户端请求自动重试 2 次。
2. 服务端推荐 systemd 托管，Restart=always。
3. 服务端可设置 MemoryMax=64M，防止意外内存膨胀。
4. 支持 journald 日志，便于排查问题。
5. 沙盒包本身零额外必填变量，未配置时默认访问本机。

安全提示：
该工具具备执行 Linux 用户权限命令的能力，请勿暴露到公网。', 'gh_271535154', 'gh_271535154', 'system_data', 'approved', '2026-06-19T02:43:19Z', '2026-06-23T15:17:16Z', '2026-06-19T02:43:19Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-magisk-module-builder', 'script', '面具模块制作工具', '🎯 全功能 Magisk/KernelSU/APatch 面具模块制作工具包 v4.', '🎯 全功能 Magisk/KernelSU/APatch 面具模块制作工具包 v4.2

