INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-mimo-video', 'script', '小米 MiMo URL视频理解', '（开头小作文，为解决群友百亿token太多特意制作，解决了使用原视频解析功能经常卡死/消耗过多流量问题，注意：URL视频最大300MB，否则会400报错）调用小米 MiMo 视频理解 API，通过视频', '（开头小作文，为解决群友百亿token太多特意制作，解决了使用原视频解析功能经常卡死/消耗过多流量问题，注意：URL视频最大300MB，否则会400报错）调用小米 MiMo 视频理解 API，通过视频 URL 让 AI 分析视频内容。支持自定义抽帧率、分辨率和提问。API 使用 api-key 头鉴权（非 Bearer Token）。', 'gh_275337600', 'gh_275337600', 'media_content', 'approved', '2026-05-28T15:13:42Z', '2026-05-30T01:49:40Z', '2026-05-28T15:13:42Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-mimo-video-async', 'script', '小米 MiMo 视频理解（异步）', '（开头小作文，此版本创新性的解决了ai在调用工具需要傻乎乎等待工具返回的问题，要是时间长了服务器可能还会断输出，现在ai可以直接将视频解析任务提交到终端后台处理，来让ai同时去做别的事，但目前由于终端', '（开头小作文，此版本创新性的解决了ai在调用工具需要傻乎乎等待工具返回的问题，要是时间长了服务器可能还会断输出，现在ai可以直接将视频解析任务提交到终端后台处理，来让ai同时去做别的事，但目前由于终端会话限制后台存在大于64个会话后会触发卡死等神秘bug，需要手动删除已完成会话，）提交后立即返回 task_id，后台终端进程处理，poll 取结果。依赖内置包 super_admin（需启用），Linux 终端需有 python3。如无法使用，优先检查：① super_admin 是否启用 ② MIMO_API_KEY 是否配置 ③ 网络是否可达 MiMo API。', 'gh_275337600', 'gh_275337600', 'automation_workflow', 'approved', '2026-05-30T00:55:47Z', '2026-05-30T01:50:18Z', '2026-05-30T00:55:47Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-mimo-video-async-batch', 'script', 'MiMo URL解析批量异步（守护进程）', '（1.2.0修复已知bug） 【功能】批量异步调用小米MiMo视频理解API，支持高并发、自动重试、进度监控。', '（1.2.0修复已知bug）
【功能】批量异步调用小米MiMo视频理解API，支持高并发、自动重试、进度监控。

【使用步骤】
① 启动守护进程（只需一次）：调用 start
② 提交任务（秒回task_id）：调用 submit_video，可连续提交多个
③ 轮询结果：调用 poll_result(task_id) 获取结果

【依赖要求】
- 必须启用 super_admin（超管）包
- 设备需有 Linux 终端 + python3
- 需配置 MIMO_API_KEY 环境变量

【默认参数】
- API端点：https://token-plan-cn.xiaomimimo.com
- 模型：mimo-v2.5
- 抽帧率：10 fps
- 分辨率：max
- 最大输出：130000 tokens
- 每批并行：5个
- 最大重试：3次
- 任务超时：10分钟

【工作原理】
1. submit_video 只写文件（.py/.json/.payload.json），不调终端，秒回
2. 守护进程读取队列，分批启动worker（每批5个并行）
3. worker发送HTTP请求到MiMo API，结果写入.json
4. 失败时自动重试（最多3次，递增等待5/10/15秒）
5. 完成后自动清理临时文件（.py/.log/.payload.json）

【文件位置】/sdcard/Download/Operit/mimo_tasks/

【无法使用时排查】
1. 检查 super_admin 包是否启用（设置→包管理→超级管理员）
2. 检查 MIMO_API_KEY 环境变量是否配置
3. 检查网络是否可达 MiMo API
4. 查看 daemon.log 了解守护进程状态

【成功率】经测试100并发成功率99%+', 'gh_275337600', 'gh_275337600', 'system_data', 'approved', '2026-05-30T01:58:17Z', '2026-06-01T02:18:10Z', '2026-05-30T01:58:17Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-minimax-api', 'script', '机能说话了（对）（MiniMax API版本）', '（接入MiniMax API后，只要有了自己捏好的音色，复制Voice ID和API key发给机，就可以直接听到机说话（不用调用本机播放器的直接说话）。没有语音条，暂时没搓。', '（接入MiniMax API后，只要有了自己捏好的音色，复制Voice ID和API key发给机，就可以直接听到机说话（不用调用本机播放器的直接说话）。没有语音条，暂时没搓。没测试，看看能不能用吧）通过 OpenAI 兼容接口连接 MiniMax 语言模型，支持对话补全和模型列表查询。需要配置 MINIMAX_API_KEY 环境变量。', 'gh_288862448', 'gh_288862448', 'search_research', 'approved', '2026-05-31T10:17:43Z', '2026-06-01T06:40:56Z', '2026-05-31T10:17:43Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-minimax-music', 'script', 'MiniMax 音乐创作', '基于 MiniMax 海螺音乐 API (v1/musicgeneration) 的 AI 音乐创作工具。支持 music-2.', '基于 MiniMax 海螺音乐 API (v1/music_generation) 的 AI 音乐创作工具。支持 music-2.6(歌词生曲)、纯音乐(is_instrumental)、翻唱(music-cover)、歌词优化器(lyrics_optimizer)、流式输出(stream)、翻唱预处理(cover_preprocess)。歌词支持结构标签[Verse][Chorus]等。返回<voice>标签可播放。环境变量：MINIMAX_MUSIC_API_KEY。', 'gh_17543777', 'gh_17543777', 'media_content', 'changes_requested', '2026-06-25T14:59:49Z', '2026-06-26T09:29:52Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-minimax-tts', 'script', 'MiniMax 语音合成', 'MiniMax 官方 TTS 专属插件。支持 303 音色、9 种情绪、18 种语气词、混合音色、发音纠正、41 种语言增强、字幕时间戳、4 维音效器、文本规范化和 LaTeX 朗读。', 'MiniMax 官方 TTS 专属插件。支持 303 音色、9 种情绪、18 种语气词、混合音色、发音纠正、41 种语言增强、字幕时间戳、4 维音效器、文本规范化和 LaTeX 朗读。支持单次/批量/对话/在线 URL 多模式。', 'gh_17543777', 'gh_17543777', 'media_content', 'withdrawn', '2026-06-25T05:19:19Z', '2026-06-26T09:30:12Z', NULL);
