INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-multi-api-draw', 'script', '多API生图', '支持配置多个 OpenAI 格式的图像生成 API，按需选择或自动轮询调用。可管理多个 API 地址、密钥和备注，实现灵活的多渠道生图。', '支持配置多个 OpenAI 格式的图像生成 API，按需选择或自动轮询调用。可管理多个 API 地址、密钥和备注，实现灵活的多渠道生图。', 'gh_87345721', 'gh_87345721', 'media_content', 'approved', '2026-06-07T07:12:29Z', '2026-06-10T18:05:02Z', '2026-06-07T07:12:29Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-multi-video-summarizer-js', 'script', '多平台视频解析（JS独立版）', '真正独立的多平台视频解析 JS 沙盒包。内嵌完整 Python 提取器源码，运行时自动写入包私有目录并执行，不依赖外部 skill 目录。支持多平台字幕/转写提取、关键帧、配置读写与缓存清理。', '真正独立的多平台视频解析 JS 沙盒包。内嵌完整 Python 提取器源码，运行时自动写入包私有目录并执行，不依赖外部 skill 目录。支持多平台字幕/转写提取、关键帧、配置读写与缓存清理。

工具包内配置一键安装依赖工具，经反复测试，完全不会有任何bug或解析失败的情况。
工具支持硅基流动的音频解析和本地音频解析，双选择方案，支持视频下载，相比其他同类解析软件，超稳定，30秒的视频，大约1分钟解析完毕', 'gh_249568371', 'gh_249568371', 'media_content', 'approved', '2026-05-03T06:36:15Z', '2026-05-03T11:48:06Z', '2026-05-03T06:36:15Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-mygo-searcher', 'script', 'MyGO 贴图搜索器', 'MyGO Searcher RESTful API 封装工具，支持搜索、浏览、随机获取 MyGO/AveMujica 动漫贴图。', 'MyGO Searcher RESTful API 封装工具，支持搜索、浏览、随机获取 MyGO/AveMujica 动漫贴图。提供健康检查、图片列表分页浏览、关键词搜索（支持繁简中文+模糊匹配）、随机图片获取、以及按ID获取图片详情等功能。

数据来源：https://mygo.miyago9267.com
原作者：miyago9267 (https://github.com/miyago9267)
开源协议：MIT License', 'gh_26619577', 'gh_26619577', 'dev_code', 'approved', '2026-05-11T07:52:24Z', '2026-05-11T10:40:28Z', '2026-05-11T07:52:24Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-ncmapi', 'script', '网易云音乐 API 增强版', '调用 NCMAPI 增强版服务（网易云音乐 API），支持搜索音乐、获取歌曲详情、播放链接、歌词、歌单等 200+ 接口。支持唤起网易云音乐 App 直接播放歌曲。', '调用 NCMAPI 增强版服务（网易云音乐 API），支持搜索音乐、获取歌曲详情、播放链接、歌词、歌单等 200+ 接口。支持唤起网易云音乐 App 直接播放歌曲。

Tip：
环境变量中的API 密钥正常来讲无需配置，Ncm项目默认是没有的
此项主要是防止你部署的ncmAPI登录你的账号后被其他人调用
我当时有考虑到部分用户不会 nginx反代ncm，特意写了一个readme, 结果发现投稿包不能看到readme，所以特此修改描述添加此内容

正文（直接发给AI即可）：
NCM后端+Nginx反向代理后端搭建', 'gh_171425200', 'gh_171425200', 'media_content', 'approved', '2026-06-06T08:53:59Z', '2026-06-11T11:26:46Z', '2026-06-06T08:53:59Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-netdiag-box', 'script', '网络诊断箱', '可以让AI调用这个工具给你的网络做一次体检。 还可以复制网站的网址丢给AI做体检。', '可以让AI调用这个工具给你的网络做一次体检。
还可以复制网站的网址丢给AI做体检。

全能网络诊断工具集：Ping连通测试、端口扫描、路由追踪、MTR路由+延迟诊断、DNS解析、反向DNS、DNS传播对比、SSL证书检查、IP归属查询、Whois查询、本地网络环境诊断、网站健康检查、HTTP头部分析、重定向链追踪、带宽测速、网络稳定性监测、子网计算。

权限说明：
大部分基础功能（端口扫描/DNS/IP归属/SSL等11项）：只需联网就行
小部分增强功能（Ping/路由追踪/MTR/稳定性等6项）：可能需要 Shizuku / ADB 无线调试', 'gh_241911916', 'gh_241911916', 'search_research', 'approved', '2026-05-03T08:27:15Z', '2026-05-03T11:47:55Z', '2026-05-03T08:27:15Z');
