INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-pexels-search', 'script', 'Pexels 图片搜索', '基于 Pexels API 的图片和视频搜索工具。支持按关键词搜索高质量免费图片、获取图片详情、浏览精选图集、搜索视频等。需要 Pexels API Key（免费，在 pexels.com 申请）。', '基于 Pexels API 的图片和视频搜索工具。支持按关键词搜索高质量免费图片、获取图片详情、浏览精选图集、搜索视频等。需要 Pexels API Key（免费，在 pexels.com 申请）。', 'gh_144799654', 'gh_144799654', 'media_content', 'approved', '2026-05-14T03:04:20Z', '2026-05-14T06:51:23Z', '2026-05-14T03:04:20Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-phoenix-tool-layer', 'script', '🦅 凤凰迷你工具层 v1.1', '融合Claude Code+Pi Agent+ECC+12-Factor的凤凰工具层。5核心+33外围+8步流水线+6权限+7钩子+6层ECC。v1.1修复12项问题并增强安全与性能', '融合Claude Code+Pi Agent+ECC+12-Factor的凤凰工具层。5核心+33外围+8步流水线+6权限+7钩子+6层ECC。v1.1修复12项问题并增强安全与性能', 'gh_246374708', 'gh_246374708', 'system_data', 'withdrawn', '2026-06-12T06:54:51Z', '2026-06-13T07:54:45Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-plugin-backup-manager', 'script', '一键备份恢复', '一键备份/恢复 Operit 插件、Sandbox 包、工作流、世界书和软件设置。', '一键备份/恢复 Operit 插件、Sandbox 包、工作流、世界书和软件设置。软件设置已统一覆盖模型配置、功能模型绑定、上下文总结、主题与显示、角色卡、语音服务、环境变量、工具权限、UI 偏好、DataStore、SharedPreferences、数据库及插件相关数据；恢复前自动快照，降低升级或清理数据导致配置丢失的风险。', 'gh_251724981', 'gh_251724981', 'system_data', 'approved', '2026-05-13T07:13:42Z', '2026-05-13T12:19:27Z', '2026-05-13T07:13:42Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-pp-ocrv6', 'script', 'PP-OCRv6 文字识别', '基于百度飞桨 PP-OCRv6 的高精度文字检测与识别工具包。支持中英文混合识别、50种语言、电路板/数码管等工业场景。默认使用 ONNX Runtime 引擎进行离线推理，无需联网。', '基于百度飞桨 PP-OCRv6 的高精度文字检测与识别工具包。支持中英文混合识别、50种语言、电路板/数码管等工业场景。默认使用 ONNX Runtime 引擎进行离线推理，无需联网。
工具包内置一个部署指引的工具，可以指导AI将PP_OCRv6部署到Operit软件内的Linux环境当中（如果没有）。目前可以进行单张图片的识别与批量识别（支持显示置信度与文字位置），也还有一些小问题。如果出现问题请评论区留言，也可以自行使用AI进行修复与改进。
注：如果根据deploy_guide进行部署时出现问题，欢迎进行反馈，并让AI自行尝试解决，推荐联网搜索相关信息再继续。', 'gh_141490153', 'gh_141490153', 'dev_code', 'approved', '2026-06-12T15:50:52Z', '2026-06-14T06:46:17Z', '2026-06-12T23:48:03Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-qqmusic', 'script', 'QQ音乐搜索与拉起播放', 'QQ音乐搜索与播放工具包。让Operit AI直接搜索QQ音乐全曲库并唤起App播放，享受你的会员音质。', 'QQ音乐搜索与播放工具包。让Operit AI直接搜索QQ音乐全曲库并唤起App播放，享受你的会员音质。搜索通过带Referer头的HTTP请求直打QQ音乐公开搜索接口，绕过跨域保护，无需AppID或AppSecret。播放通过qqmusic:// URL Scheme唤起QQ音乐App，一步到位。需要同时激活extended_http_tools包。使用方法：说用QQ音乐搜某某歌或QQ音乐播放某某歌即可。', 'gh_101791514', 'gh_101791514', 'search_research', 'approved', '2026-06-13T06:12:04Z', '2026-06-14T06:43:22Z', '2026-06-13T06:12:04Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-qr-generator', 'script', '二维码生成器（文本/链接）', '通过链接或文本生成 QR 码图片，保存在 /sdcard/Download 文件夹。支持自定义文件名、尺寸和纠错等级。', '通过链接或文本生成 QR 码图片，保存在 /sdcard/Download 文件夹。支持自定义文件名、尺寸和纠错等级。', 'gh_171425200', 'gh_171425200', 'media_content', 'approved', '2026-06-03T15:38:40Z', '2026-06-04T03:44:01Z', '2026-06-03T15:39:39Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-qrcode-generator', 'script', '二维码生成器', '生成二维码图片。基于 https://api.2dcode.biz 接口，将文本转换为二维码并返回 Markdown 图片输出。', '生成二维码图片。基于 https://api.2dcode.biz 接口，将文本转换为二维码并返回 Markdown 图片输出。', 'gh_193030174', 'gh_193030174', 'media_content', 'approved', '2026-05-03T14:17:38Z', '2026-05-03T16:57:03Z', '2026-05-03T14:17:38Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-query-memory-wrapper', 'script', 'AI记忆检索的时间戳调整', '对 querymemory方法的包装版本，自动将 starttime 和 endtime 截断到 YYYY-MM 精度（去掉日和时）。', '对 query_memory方法的包装版本，自动将 start_time 和 end_time 截断到 YYYY-MM 精度（去掉日和时）。

使用情景：当描述某个时间时，ai时常以该时间去查询记忆库内记忆块的时间戳。
假设你手动保存记忆，保存的时间戳很容易和描述的时间对不上，导致被直接过滤无法检索。
本方法扩大了对记忆检索的时间冗余，尽管有一点额外消耗，但可以增加AI检索记忆库的准确性，启用后将自动使用本方法。', 'gh_58496163', 'gh_58496163', 'search_research', 'withdrawn', '2026-05-02T13:26:10Z', '2026-05-02T13:36:55Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-qweather', 'script', '和风天气-天气查询与预报', '和风天气 API 集成工具包，提供城市搜索、实时天气、逐日/逐小时天气预报、分钟级降水预报、天气预警、格点实时天气查询和实时空气质量查询功能。需要自行前往dev.qweather.', '和风天气 API 集成工具包，提供城市搜索、实时天气、逐日/逐小时天气预报、分钟级降水预报、天气预警、格点实时天气查询和实时空气质量查询功能。需要自行前往dev.qweather.com注册免费账号，获取api host和apikey并填入环境变量。
（2026/5/2）1.2.4更新：
-完善了错误处理机制', 'gh_141490153', 'gh_141490153', 'search_research', 'approved', '2026-04-30T23:31:39Z', '2026-05-01T17:20:36Z', '2026-04-30T23:31:39Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-radical-mode', 'script', '超激进模式', '超激进模式 — 仅当用户引用该包（@radicalmode ）时调用。将对话模型的创造力参数暴力拉到极限——高温、高随机、低惩罚、去约束。切换前自动存档原参数。支持激进派对、平稳恢复、状态查询。', '超激进模式 — 仅当用户引用该包（@radical_mode ）时调用。将对话模型的创造力参数暴力拉到极限——高温、高随机、低惩罚、去约束。切换前自动存档原参数。支持激进派对、平稳恢复、状态查询。', 'gh_271535154', 'gh_271535154', 'search_research', 'pending', '2026-06-25T06:33:49Z', '2026-06-25T06:33:49Z', NULL);
