INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-sandboxpackage-dev', 'script', '📦 Sandbox Package 开发工具包', 'Operit Sandbox Package 全能开发工具包。提供完整的包开发环境安装/更新、类型定义查询、开发指南查阅、示例包参考、项目骨架创建等一站式开发能力。', 'Operit Sandbox Package 全能开发工具包。提供完整的包开发环境安装/更新、类型定义查询、开发指南查阅、示例包参考、项目骨架创建等一站式开发能力。基于官方 SandboxPackage_DEV Skill 封装，适合 AI 辅助或手动开发 Sandbox Package 使用。', 'gh_246374708', 'gh_246374708', 'search_research', 'changes_requested', '2026-06-16T03:04:29Z', '2026-06-21T14:48:19Z', NULL);
