INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-secretary', 'script', '小秘书', '感谢小红书@momo 老师提供的小秘书灵感！ 插件说明： 将任务委派给「小秘书」角色卡（便宜模型）执行，节省主模型token。', '感谢小红书@momo 老师提供的小秘书灵感！
插件说明：
将任务委派给「小秘书」角色卡（便宜模型）执行，节省主模型token。已验证：MCP论坛浏览、长文件读取（含md,json等代码文件）、百度搜索、记忆读取等。不支持：音频/图片附件。主模型仅消耗1次工具调用。
使用方法：
1.创建一个角色卡，名为「小秘书」
2.把工具/沙盒包/skill/mcp权限在「小秘书」角色卡中打开
3.在「小秘书」角色卡的高级选项>绑定对话模型>指定固定配置中绑定便宜模型
4.把本插件权限开放给主模型，让主模型自行调用即可
注意：有些太便宜的模型可能会幻觉严重，适当选用合适的模型即可，不然会变成迷糊小秘书。
5.小秘书配套提示词见工具描述（放角色卡>高级选项>自定义提示词中）', 'gh_275441427', 'gh_275441427', 'chat_communication', 'approved', '2026-05-25T06:24:51Z', '2026-05-25T15:05:31Z', '2026-05-25T06:24:51Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-self-evolution-analyzer', 'script', '自进化分析器', '自进化分析器v0.7.0：分析系统能力缺口、工作流健康度、模型配置参数最优性，生成并自动执行修复方案，集成系统健康协调检查，支持工作流自愈和多维度自进化', '自进化分析器v0.7.0：分析系统能力缺口、工作流健康度、模型配置参数最优性，生成并自动执行修复方案，集成系统健康协调检查，支持工作流自愈和多维度自进化', 'gh_246374708', 'gh_246374708', 'automation_workflow', 'withdrawn', '2026-06-06T13:50:16Z', '2026-06-11T11:20:08Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-semble', 'script', 'Semble 代码搜索', '快速准确的代码语义搜索工具。通过自然语言或代码片段搜索代码库。支持语义搜索、关联发现、token 统计和 agent 配置生成。', '快速准确的代码语义搜索工具。通过自然语言或代码片段搜索代码库。支持语义搜索、关联发现、token 统计和 agent 配置生成。', 'gh_46757693', 'gh_46757693', 'search_research', 'approved', '2026-05-29T16:51:55Z', '2026-05-30T01:48:59Z', '2026-05-29T17:15:28Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-sensenova-draw', 'script', 'SenseNova 绘图', '使用商汤 SenseNova 官方图像生成接口 (/v1/images/generations) 生成图片，基于 SenseNova U1 Fast 模型，以信息图生成为特色；结果保存到本地 /sdc', '使用商汤 SenseNova 官方图像生成接口 (/v1/images/generations) 生成图片，基于 SenseNova U1 Fast 模型，以信息图生成为特色；结果保存到本地 /sdcard/Download/Operit/plugins/draw/sensenova_draw/draws/ 目录，并返回 Markdown 图片提示。', 'gh_275337600', 'gh_275337600', 'media_content', 'approved', '2026-05-27T00:32:48Z', '2026-05-27T08:30:41Z', '2026-05-27T00:32:48Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-shizuku-manager', 'script', 'Shizuku启动器', '通过Intent广播自动启动/停止/重启Shizuku服务，让Operit帮你管理Shizuku，无需频繁切换软件。 适用场景 Shizuku服务经常意外断开，导致需要手动重新启动。', '通过Intent广播自动启动/停止/重启Shizuku服务，让Operit帮你管理Shizuku，无需频繁切换软件。

适用场景
Shizuku服务经常意外断开，导致需要手动重新启动。本工具可以让Operit在Shizuku断开时自动恢复。

前置条件
-已安装Shizuku,并设置为ADB无线模式
-已开启开发者模式
-shizuku支持自启动，且已开启
-需执行一次权限授予（Shizuku运行时
   pm grant moe.shizuku.privileged.api android.permission.WRITE_SECURE_SETTINGS
   可通过Operit的 `super_admin:shell` 工具执行
   
更新说明
-添加了环境配置,首次使用请配置auth和port环境变量。
-简化工具,从环境配置中获取端口和auth,减少token消耗', 'gh_275434479', 'gh_275434479', 'dev_code', 'approved', '2026-05-30T07:29:49Z', '2026-06-01T08:24:09Z', '2026-05-30T07:29:49Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-shizuku-shell-next', 'script', 'ShizukuShell NEXT', '让 机 通过 Operit 宿主的 Shizuku/Root Shell 通道执行 Android 系统命令。提供状态检查、命令执行、包管理、设置读写、AppOps 授权等常用提权操作封装。', '让 机 通过 Operit 宿主的 Shizuku/Root Shell 通道执行 Android 系统命令。提供状态检查、命令执行、包管理、设置读写、AppOps 授权等常用提权操作封装。附有危险命令阻拦机制。', 'gh_271535154', 'gh_271535154', 'dev_code', 'withdrawn', '2026-06-19T07:38:14Z', '2026-06-25T03:11:04Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-skill-recommender', 'script', '智能技能推荐', '智能技能推荐工具。自动扫描已安装技能，根据用户输入推荐最匹配的技能。覆盖编程、调试、部署、重构、安全审计、逆向分析、测试、DevOps、搜索、记忆管理等全部领域。', '智能技能推荐工具。自动扫描已安装技能，根据用户输入推荐最匹配的技能。覆盖编程、调试、部署、重构、安全审计、逆向分析、测试、DevOps、搜索、记忆管理等全部领域。', 'gh_288296953', 'gh_288296953', 'dev_code', 'approved', '2026-06-17T12:40:07Z', '2026-06-17T17:00:38Z', '2026-06-17T12:40:07Z');
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-statistics-tools', 'script', '统计学工具包', '统计学工具包：一元线性回归与卡方独立性检验。免责声明：本工具包代码由AI生成，仅供参考和学习使用 （终于不用手算卡方了555...）', '统计学工具包：一元线性回归与卡方独立性检验。免责声明：本工具包代码由AI生成，仅供参考和学习使用
