INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('script-sub-agent-manager', 'script', '子Agent管理器', '子Agent管理器。自动绑定空白角色卡或空白卡创建上下文纯净的子Agent，主Agent自定义任务（审核/开发/分析等）。', '子Agent管理器。自动绑定空白角色卡或空白卡创建上下文纯净的子Agent，主Agent自定义任务（审核/开发/分析等）。init_workspace→工作→review 派发→destroy_reviewer 清理。教程见 help。', 'gh_217558008', 'gh_217558008', 'dev_code', 'approved', '2026-05-20T15:36:47Z', '2026-05-23T15:00:04Z', '2026-05-21T02:57:41Z');
