INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-ai-analyzer', 'skill', 'ai-analyzer', 'AI驱动的综合健康分析系统，整合多维度健康数据，提供风险预测与个性化建议，支持智能问答和AI健康报告生成。', 'AI驱动的综合健康分析系统，整合多维度健康数据，提供风险预测与个性化建议，支持智能问答和AI健康报告生成。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:09:00Z', '2026-02-20T16:09:00Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-emergency-card', 'skill', 'emergency-card', '该技能可生成紧急医疗信息摘要卡片，用于旅行、就诊或急救场景。它能从健康数据中提取关键信息（如严重过敏、当前用药），并按优先级排序，支持生成JSON、文本、HTML等多种格式的输出。', '该技能可生成紧急医疗信息摘要卡片，用于旅行、就诊或急救场景。它能从健康数据中提取关键信息（如严重过敏、当前用药），并按优先级排序，支持生成JSON、文本、HTML等多种格式的输出。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:29:53Z', '2026-02-20T16:29:53Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-family-health-analyzer', 'skill', 'family-health-analyzer', '本技能提供家庭健康数据的深度分析，包括遗传风险评估、家族疾病模式识别和个性化预防建议，帮助用户了解家族健康趋势并制定预防措施。', '本技能提供家庭健康数据的深度分析，包括遗传风险评估、家族疾病模式识别和个性化预防建议，帮助用户了解家族健康趋势并制定预防措施。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:29:54Z', '2026-02-20T16:29:54Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-fitness-analyzer', 'skill', 'fitness-analyzer', '该技能专注于分析运动数据，识别运动模式，评估健身进展，并提供个性化训练建议，同时支持与慢性病数据的关联分析。', '该技能专注于分析运动数据，识别运动模式，评估健身进展，并提供个性化训练建议，同时支持与慢性病数据的关联分析。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:29:56Z', '2026-02-20T16:29:56Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-food-database-query', 'skill', 'food-database-query', '本技能提供全面的食物营养数据库查询功能，支持食物营养信息查询、比较、推荐和自动营养计算，帮助用户进行健康饮食管理。', '本技能提供全面的食物营养数据库查询功能，支持食物营养信息查询、比较、推荐和自动营养计算，帮助用户进行健康饮食管理。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:29:59Z', '2026-02-20T16:29:59Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-goal-analyzer', 'skill', 'goal-analyzer', '该技能专注于健康目标管理，通过SMART原则验证目标、追踪进度、分析习惯养成，并提供与营养、运动等数据的关联分析，生成可视化报告以辅助健康改善。', '该技能专注于健康目标管理，通过SMART原则验证目标、追踪进度、分析习惯养成，并提供与营养、运动等数据的关联分析，生成可视化报告以辅助健康改善。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:30:01Z', '2026-02-20T16:30:01Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-health-trend-analyzer', 'skill', 'health-trend-analyzer', '分析一段时间内健康数据的趋势和模式，关联药物、症状、生命体征等指标的变化，识别令人担忧的趋势并提供数据驱动的洞察。支持多维度分析、相关性分析和交互式可视化报告。', '分析一段时间内健康数据的趋势和模式，关联药物、症状、生命体征等指标的变化，识别令人担忧的趋势并提供数据驱动的洞察。支持多维度分析、相关性分析和交互式可视化报告。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:30:03Z', '2026-02-20T16:30:03Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-mental-health-analyzer', 'skill', 'mental-health-analyzer', '该技能专注于分析心理健康数据，识别情绪模式，评估危机风险，并提供个性化建议。它还能关联分析睡眠、运动、营养等其他健康数据对心理状态的影响。', '该技能专注于分析心理健康数据，识别情绪模式，评估危机风险，并提供个性化建议。它还能关联分析睡眠、运动、营养等其他健康数据对心理状态的影响。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:30:05Z', '2026-02-20T16:30:05Z', NULL);
