INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-occupational-health-analyzer', 'skill', 'occupational-health-analyzer', '该技能专注于职业健康数据分析，可评估工作相关健康风险并提供个性化改进建议，同时支持与睡眠、运动等健康数据的关联分析。', '该技能专注于职业健康数据分析，可评估工作相关健康风险并提供个性化改进建议，同时支持与睡眠、运动等健康数据的关联分析。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:30:09Z', '2026-02-20T16:30:09Z', NULL);
