INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-huifer-claude-ally-health-claude-skills-sexual-health-analyzer', 'skill', 'sexual-health-analyzer', '本技能提供全面的性健康数据分析功能，包括IIEF-5评分分析、STD筛查管理、避孕效果评估及性活动统计，并与用药、慢性病、心理、营养等模块进行深度关联分析。', '本技能提供全面的性健康数据分析功能，包括IIEF-5评分分析、STD筛查管理、避孕效果评估及性活动统计，并与用药、慢性病、心理、营养等模块进行深度关联分析。请注意，所有分析结果仅供参考，不能替代专业医疗诊断。', 'gh_-120560926225564', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:30:16Z', '2026-02-20T16:30:16Z', NULL);
