INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-benchling-integration', 'skill', 'benchling-integration', '该技能提供Benchling研发平台的API集成能力，支持通过Python SDK管理生物注册实体、库存、电子实验记录及自动化工作流，实现实验室数据管理自动化。', '该技能提供Benchling研发平台的API集成能力，支持通过Python SDK管理生物注册实体、库存、电子实验记录及自动化工作流，实现实验室数据管理自动化。', 'gh_-222905189975', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:31:02Z', '2026-02-20T16:31:02Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-biopython', 'skill', 'biopython', 'Biopython 提供全面的分子生物学计算工具，适用于序列操作、文件解析、系统发育分析及程序化访问NCBI数据库等生物信息学任务。', 'Biopython 提供全面的分子生物学计算工具，适用于序列操作、文件解析、系统发育分析及程序化访问NCBI数据库等生物信息学任务。', 'gh_-222905189975', 'gh_66207760', 'system_data', 'changes_requested', '2026-02-20T16:31:04Z', '2026-02-20T16:31:04Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-biorxiv-database', 'skill', 'biorxiv-database', '该技能提供高效的bioRxiv预印本数据库搜索工具，支持按关键词、作者、日期和类别检索文献元数据，并可下载PDF全文，适用于生命科学领域的文献调研与分析。', '该技能提供高效的bioRxiv预印本数据库搜索工具，支持按关键词、作者、日期和类别检索文献元数据，并可下载PDF全文，适用于生命科学领域的文献调研与分析。', 'gh_-222905189975', 'gh_66207760', 'search_research', 'changes_requested', '2026-02-20T16:31:06Z', '2026-02-20T16:31:06Z', NULL);
