INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-pymatgen', 'skill', 'pymatgen', 'Pymatgen是用于材料科学的Python工具包，支持晶体结构操作、相图计算、能带结构分析，并能与Materials Project数据库集成，适用于计算材料科学研究。', 'Pymatgen是用于材料科学的Python工具包，支持晶体结构操作、相图计算、能带结构分析，并能与Materials Project数据库集成，适用于计算材料科学研究。', 'gh_-222905189975', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:34:01Z', '2026-02-20T16:34:01Z', NULL);
