INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-scikit-bio', 'skill', 'scikit-bio', 'scikit-bio是一个用于生物数据分析的Python工具包，支持序列分析、系统发育树构建、多样性指标计算以及微生物组分析等核心生物信息学任务。', 'scikit-bio是一个用于生物数据分析的Python工具包，支持序列分析、系统发育树构建、多样性指标计算以及微生物组分析等核心生物信息学任务。', 'gh_-222905189975', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:34:42Z', '2026-02-20T16:34:42Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-k-dense-ai-claude-scientific-skills-scientific-skills-scikit-learn', 'skill', 'scikit-learn', '该技能提供使用scikit-learn进行机器学习的全面指导，涵盖分类、回归、聚类、数据预处理、模型评估及构建生产级ML流水线等核心任务。', '该技能提供使用scikit-learn进行机器学习的全面指导，涵盖分类、回归、聚类、数据预处理、模型评估及构建生产级ML流水线等核心任务。', 'gh_-222905189975', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:34:44Z', '2026-02-20T16:34:44Z', NULL);
