INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-kikiba0152-character-card-converter-alskills', 'skill', 'character-card-converter-AlSkills', 'Operit 平台的 Skill，用于将任意来源的角色卡（SillyTavern V1/V2、TavernAI、Character.AI JSON 等）统一转为完整的 V3 角色卡，含智能拆分补齐。', 'Operit 平台的 Skill，用于将任意来源的角色卡（SillyTavern V1/V2、TavernAI、Character.AI JSON 等）统一转为完整的 V3 角色卡，含智能拆分补齐。', 'gh_-156292973258070', 'gh_101791514', 'dev_code', 'changes_requested', '2026-05-26T08:17:31Z', '2026-06-19T12:46:37Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-kkkkhazix-khazix-skills-neat-freak', 'skill', 'neat-freak（洁癖）', '会话结束后对项目文档和记忆进行洁癖级审查与 同步，自动检查并同步 README、docs、 CLAUDE.md/AGENTS.md 和 Agent 记忆，适合阶段收尾、交接和文档清理。', '会话结束后对项目文档和记忆进行洁癖级审查与 同步，自动检查并同步 README、docs、 CLAUDE.md/AGENTS.md 和 Agent 记忆，适合阶段收尾、交接和文档清理。', 'gh_-84458583902694', 'gh_95321008', 'dev_code', 'changes_requested', '2026-05-02T10:38:31Z', '2026-05-29T16:56:54Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-kkkkhazix-khazix-skills-skill-evolution-manager', 'skill', 'skill-evolution-manager', 'skill-evolution-manager', '专门用于在对话结束时，根据用户反馈和对话内容总结优化并迭代现有 Skills 的核心工具。它通过吸取对话中的“精华”（如成功的解决方案、失败的教训、特定的代码规范）来持续演进 Skills 库。', 'gh_-84458583902694', 'gh_126325311', 'dev_code', 'changes_requested', '2026-01-24T11:21:42Z', '2026-02-20T16:05:43Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-komal-skynet-claude-skill-homeassistant', 'skill', 'claude-skill-homeassistant', '提供专业的Home Assistant配置管理，支持远程SSH与hass-cli访问、自动化验证、日志分析及Lovelace面板优化，实现高效部署与迭代工作流。', '提供专业的Home Assistant配置管理，支持远程SSH与hass-cli访问、自动化验证、日志分析及Lovelace面板优化，实现高效部署与迭代工作流。', 'gh_-275120951385284', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:09:04Z', '2026-02-20T16:09:04Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-kreuzberg-dev-kreuzberg-skills-kreuzberg', 'skill', 'kreuzberg', 'Kreuzberg 是一款高性能文档智能库，支持从超过 75 种文件格式中提取文本、表格、元数据和图像，并提供 Python、Node.js、Rust 等多种语言的 API 与 CLI 工具。', 'Kreuzberg 是一款高性能文档智能库，支持从超过 75 种文件格式中提取文本、表格、元数据和图像，并提供 Python、Node.js、Rust 等多种语言的 API 与 CLI 工具。', 'gh_-267499029401657', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:09:04Z', '2026-02-20T16:09:04Z', NULL);
INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-lackeyjb-playwright-skill-skills-playwright-skill', 'skill', 'playwright-skill', '基于Playwright的完整浏览器自动化技能，可自动检测开发服务器并执行网页测试、表单填写、截图和响应式设计验证等任务。', '基于Playwright的完整浏览器自动化技能，可自动检测开发服务器并执行网页测试、表单填写、截图和响应式设计验证等任务。', 'gh_-75026854102191', 'gh_66207760', 'dev_code', 'changes_requested', '2026-02-20T16:09:03Z', '2026-02-20T16:09:03Z', NULL);
