INSERT OR IGNORE INTO market_entries (id, type, title, description, detail, author_id, publisher_id, category_id, state_code, created_at, updated_at, published_at) VALUES ('skill-github-com-rimagination-bili-note', 'skill', 'Bili Note', 'Bili Note 20260621 Bili Note 是一个面向知识库的 B 站视频与图文笔记工具：完整归档字幕、图文正文、图片与评论，按内容信息量和质量动态控制笔记长度，把 B 站内容整理成可学', 'Bili Note
20260621
Bili Note 是一个面向知识库的 B 站视频与图文笔记工具：完整归档字幕、图文正文、图片与评论，按内容信息量和质量动态控制笔记长度，把 B 站内容整理成可学习、可检索、可追问的 Markdown 笔记。

它的核心特点是：

完整归档：保存完整字幕、图文正文、图片、完整评论、元数据和证据索引，主笔记中的关键判断可以通过论文式编号链接回到原文位置复核。
非固定长度：不把短视频和长课程压成同样字数，而是按信息量和内容结构决定提炼粒度。
质量感知：结合内容热度、互动质量、评论讨论度和发布时间等信号调整笔记预算，让更值得深读的内容获得更充分的整理。
写前定标：先根据原始材料生成推荐字数、压缩比和写作粒度，再开始写笔记；写后评分只用于验收和微调。
它的目标不是把内容压成几句摘要，而是生成一份“学完这节课或读完这篇教程之后真的有收获”的学习型笔记。

适合什么
提炼 B 站技术视频、课程、观点视频、多 P 系列课和图文/动态/opus 长文。
把完整字幕、图文正文、图片、评论、元数据和证据索引长期保存到知识库。
为人类阅读和 Agent 后续问答准备可引用的证据。
根据视频时长、字幕字数、图文正文量、互动热度和评论量控制笔记详略，避免长课、短视频和长图文都被压成同样长度。
先用预算确定目标字数和结构密度，再写主笔记，减少写完后大幅返工。
输出内容
一次完整提取会生成两层结果：面向阅读的主笔记，以及面向复核和追问的原始材料包。主笔记会先依据材料包里的预算确定详略，再组织学习收获、关键概念、方法流程、实践清单和证据位置；材料包保存完整字幕或图文正文、图片、评论、元数据、JSONL 索引、写前预算和写后评分结果。', 'gh_-116157322725612', 'gh_49579515', 'docs_knowledge', 'changes_requested', '2026-06-21T14:11:45Z', '2026-06-23T15:18:58Z', NULL);
