INSERT OR IGNORE INTO artifact_nodes (id, project_id, version_id, node_key, runtime_pkg, display_name, description, sort_order, created_at, updated_at) VALUES ('package-auto-memory-project-node-398cd9c2-aae0-406e-bc36-e6eebd65beb4', 'package-auto-memory-project', 'package-auto-memory-v-1-0-0', '398cd9c2-aae0-406e-bc36-e6eebd65beb4', 'auto_memory', 'automemory', '在每次对话时，自动根据用户输入提取历史记忆，无缝注入上下文。实现跨窗口记忆连贯，保持人设和话题不中断。（注：只读不写，历史记忆需自行存入）', 0, '2026-06-28T12:23:10.489Z', '2026-06-28T12:23:10.489Z');
