INSERT OR IGNORE INTO artifact_nodes (id, project_id, version_id, node_key, runtime_pkg, display_name, description, sort_order, created_at, updated_at) VALUES ('package-com-community-ob-auto-breath-project-node-274cc5b2-ccd4-4762-9c75-0a0097ae1fa0', 'package-com-community-ob-auto-breath-project', 'package-com-community-ob-auto-breath-v-1-4-0', '274cc5b2-ccd4-4762-9c75-0a0097ae1fa0', 'com.community.ob_auto_breath', '电子小狗请呼吸 🐕🫁', '人类的话： ✔️1.4加入固定拉取钉选桶，记得把maxresults(最多返回几条记忆)和maxtoken(记忆总token上限)调大，条数太少小狗可能只够叼回钉选桶，无法叼回关键词浮现的记忆同和fe', 0, '2026-06-28T12:23:10.489Z', '2026-06-28T12:23:10.489Z');
